import math
from functools import reduce


class Solution:
    def maxScore(self, nums):
        n = len(nums)

        def score(arr):
            if not arr:
                return 0
            g = reduce(math.gcd, arr)
            l = reduce(lambda a, b: a * b // math.gcd(a, b), arr)
            return g * l

        best = score(nums)
        for i in range(n):
            rest = nums[:i] + nums[i + 1:]
            best = max(best, score(rest))
        return best

