var maxScore = function(nums) {
    const gcd = (a, b) => { while (b) { [a, b] = [b, a % b]; } return a; };
    const n = nums.length;
    const prefixGcd = new Array(n + 1).fill(0);
    const suffixGcd = new Array(n + 1).fill(0);
    const prefixLcm = new Array(n + 1).fill(1);
    const suffixLcm = new Array(n + 1).fill(1);
    for (let i = 0; i < n; i++) {
        prefixGcd[i + 1] = gcd(prefixGcd[i], nums[i]);
        prefixLcm[i + 1] = prefixLcm[i] * nums[i] / gcd(prefixLcm[i], nums[i]);
    }
    for (let i = n - 1; i >= 0; i--) {
        suffixGcd[i] = gcd(suffixGcd[i + 1], nums[i]);
        suffixLcm[i] = suffixLcm[i + 1] * nums[i] / gcd(suffixLcm[i + 1], nums[i]);
    }
    let best = prefixGcd[n] * prefixLcm[n];
    for (let i = 0; i < n; i++) {
        const g = gcd(prefixGcd[i], suffixGcd[i + 1]);
        const l = prefixLcm[i] * suffixLcm[i + 1] / gcd(prefixLcm[i], suffixLcm[i + 1]);
        const score = g * l;
        if (score > best) best = score;
    }
    return best;
};
